import tippy from "tippy.js";
import "tippy.js/dist/tippy.css";

window.addEventListener("DOMContentLoaded", () => {
  tippy("[data-tippy-content]");

  const copyTippy = tippy("#copy", {
    content: "Copiar",
    hideOnClick: false,
  })[0];

  const btnCopy = document.querySelector("#copy .btn");

  if (!btnCopy) {
    return;
  }

  btnCopy.addEventListener("click", async function () {
    try {
      await navigator.clipboard.writeText("marianofrank@hotmail.com");
      copyTippy.setContent("Copiado ✅");
    } catch {
      copyTippy.setContent("Ocurrió un error ⛔");
    }
  });

  btnCopy.addEventListener("mouseleave", function () {
    setTimeout(() => {
      copyTippy.setContent("Copiar");
    }, 500);
  });
});
