document.addEventListener("DOMContentLoaded", () => {
  if (window.location.pathname !== "/") {
    return;
  }
  const wordsToType = document
    .querySelector("span[words]")
    .getAttribute("words")
    .split(",");
  const typer = document.querySelector("span[words]");
  const typingSpeed = parseInt(typer.getAttribute("typing-speed")) || 70;
  const typingDelay_write =
    parseInt(typer.getAttribute("typing-delay-write")) || 700;
  const typingDelay_remove =
    parseInt(typer.getAttribute("typing-delay-remove")) || 700;

  let currentWordIndex = 0,
    currentCharacterIndex = 0;

  function type() {
    let wordToType = wordsToType[currentWordIndex % wordsToType.length];

    if (currentCharacterIndex < wordToType.length) {
      typer.innerHTML += wordToType[currentCharacterIndex++];
      setTimeout(type, typingSpeed);
    } else {
      //una vez esta escrito espera el delay para borrar
      setTimeout(erase, typingDelay_remove);
    }
  }
  function erase() {
    let wordToType = wordsToType[currentWordIndex % wordsToType.length];
    if (currentCharacterIndex > 0) {
      typer.innerHTML = wordToType.substr(0, --currentCharacterIndex - 1);
      setTimeout(erase, typingSpeed);
    } else {
      currentWordIndex++;
      //una vez borrado espera el delay para arrancar a escribir
      setTimeout(type, typingDelay_write);
    }
  }

  window.onload = function () {
    type();
  };
});
