window.addEventListener("DOMContentLoaded", () => {
  //Sonido Click
  
  const sound_click = new Audio("../public/sounds/click.wav");
  sound_click.volume = 0.5;
  const btnsForSound = document.querySelectorAll(".btn , .btn_icon");

  const handleClickEvent = (btn) => {
    sound_click.play();
    btn.classList.add("clicked");
  };

  btnsForSound.forEach((btnForSound) => {
    btnForSound.addEventListener("click", (e) => {
      if (btnForSound.tagName === "A") {
        e.preventDefault();
        setTimeout(() => {
          if (btnForSound.getAttribute("target") === "_blank") {
            window.open(btnForSound.href, "_blank");
            return;
          }
          window.location = btnForSound.href;
        }, 200);
      }
    });

    btnForSound.addEventListener("mousedown", () =>
      handleClickEvent(btnForSound)
    );
    btnForSound.addEventListener("touchstart", () =>
      handleClickEvent(btnForSound)
    );

    btnForSound.addEventListener("click", () => {
      setTimeout(() => {
        btnForSound.classList.remove("clicked");
      }, 30);
    });
    btnForSound.addEventListener("mouseleave", () => {
      setTimeout(() => {
        btnForSound.classList.remove("clicked");
      }, 30);
    });
  });
});
