window.addEventListener("DOMContentLoaded", () => {
  const zoomElements = document.querySelectorAll(".zoom");

  zoomElements.forEach((element) => {
    
    const computedStyle = window.getComputedStyle(element);
    const bgImage = computedStyle.getPropertyValue("background-image");
    element.style.backgroundImage = "none";
    
    element.addEventListener("mousemove", (e) => {
      element.style.backgroundImage = bgImage;
      var zoomer = e.currentTarget;
      var rect = zoomer.getBoundingClientRect();
      var offsetX = e.clientX - rect.left;
      var offsetY = e.clientY - rect.top;

      // Ajustar el rango de -10 a 110 para permitir espacio adicional alrededor del contenedor
      var x = (offsetX / zoomer.offsetWidth) * 120 - 10;
      var y = (offsetY / zoomer.offsetHeight) * 120 - 10;

      // Limitar los valores de x e y al rango de -10 a 110
      x = Math.max(-10, Math.min(110, x));
      y = Math.max(-10, Math.min(110, y));

      zoomer.style.backgroundPosition = x + "% " + y + "%";

      //ocultamos la imagen estatica
      element.querySelector(".project-img-explain").style.opacity = 0;
    });

    element.addEventListener("mouseleave", (e) => {
      element.querySelector(".project-img-explain").style.opacity = 1;
      element.style.backgroundImage = "none";
    });
  });
});
